class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        queue = [s]
        visited = {s}
        found = False
        res = []
        while queue:
            cur = queue.pop(0)
            if self.isValid(cur):
                found = True
                res.append(cur)
            if found:
                continue
            for i in range(len(cur)):
                if cur[i] not in ('(', ')'):
                    continue
                new_str = cur[:i] + cur[i+1:]
                if new_str not in visited:
                    queue.append(new_str)
                    visited.add(new_str)
        return res

    def isValid(self, s: str) -> bool:
        count = 0
        for c in s:
            if c == '(':
                count += 1
            elif c == ')':
                if count == 0:
                    return False
                count -= 1
        return count == 0
